import { AST } from "../typescript_module/index.js";
/**
 * Locatable is a base class that any Dagger object can extend from to
 * provide a location method.
 */
export class Locatable {
    __node;
    constructor(__node) {
        this.__node = __node;
    }
    getLocation() {
        return AST.getNodeLocation(this.__node);
    }
}
